// 2. Simulated Network Latency Hook
function useSimulatedNetwork(data, delay = 600) {
  const [loading, setLoading] = useState(true);
  useEffect(() => {
    setLoading(true);
    const timer = setTimeout(() => setLoading(false), delay);
    return () => clearTimeout(timer);
  }, [data]);
  return loading;
}

// 3. Skeleton Loader Component
function Skeleton({ width = "100%", height = 20, borderRadius = 8, mb = 0 }) {
  return (
    <div style={{ 
      width, height, borderRadius, marginBottom: mb,
      background: "linear-gradient(90deg, var(--paper-3) 25%, var(--line) 50%, var(--paper-3) 75%)",
      backgroundSize: "200% 100%", animation: "skeleton-loading 1.5s infinite" 
    }} />
  );
}

// 4. AI HR Copilot Component — wired to real Anthropic API
function AICopilot({ data }) {
  const [isOpen, setIsOpen] = useState(false);
  const SYSTEM_PROMPT = `You are Vinpro Intelligence, an expert HR AI assistant embedded in the Connect by Vinpro HRMS platform. You help HR admins, employers, and clients with:
- Payroll queries, compliance questions, leave policy guidance
- Drafting HR communications (offer letters, warning letters, check-in emails)
- Explaining Indian statutory requirements (PF, ESI, TDS, Gratuity, POSH)
- Analysing attendance patterns and performance data
- EOR (Employer of Record) contract guidance and billing questions

Keep responses concise, practical and professional. Use bullet points for lists. Be direct.`;

  const [messages, setMessages] = useState([
    { role: "assistant", text: "Hi! I'm Vinpro AI. Ask me anything — payroll compliance, drafting HR letters, attendance analysis, or EOR queries. How can I help?" }
  ]);
  const [input, setInput] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [error, setError] = useState(null);
  const messagesEndRef = React.useRef(null);

  React.useEffect(() => {
    if (messagesEndRef.current) messagesEndRef.current.scrollIntoView({ behavior: "smooth" });
  }, [messages, isTyping]);

  const handleSend = async () => {
    const text = input.trim();
    if (!text || isTyping) return;
    setInput("");
    setError(null);
    // Demo event logging
    if (window.__vinproLogEvent) window.__vinproLogEvent("ai_question", { question: text });
    const newMessages = [...messages, { role: "user", text }];
    setMessages(newMessages);
    setIsTyping(true);

    // Build API messages (exclude initial assistant greeting from history to save tokens)
    const apiMessages = newMessages
      .filter((_, i) => i > 0) // skip greeting
      .map(m => ({ role: m.role === "assistant" ? "assistant" : "user", content: m.text }));

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: SYSTEM_PROMPT,
          messages: apiMessages,
        }),
      });
      if (!res.ok) throw new Error(`API error ${res.status}`);
      const json = await res.json();
      const reply = (json.content || []).map(b => b.text || "").join("").trim();
      setMessages(prev => [...prev, { role: "assistant", text: reply || "Sorry, I couldn't generate a response." }]);
    } catch (err) {
      setError("Could not reach Vinpro AI. Check your connection and try again.");
    } finally {
      setIsTyping(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSend(); }
  };

  const QUICK_PROMPTS = [
    "Draft a late attendance check-in email",
    "Explain PF contribution rules for FY 2026-27",
    "What are notice period norms in India?",
  ];

  return (
    <>
      <button id="demo-ai-btn" onClick={() => setIsOpen(true)} style={{ position:"fixed", bottom:24, right:24, background:"var(--teal)", color:"#fff", border:"none", borderRadius:50, padding:"12px 20px", boxShadow:"var(--shadow-lg)", fontWeight:600, display:"flex", gap:8, alignItems:"center", zIndex:9000 }}>
        ✨ Ask AI
      </button>
      {isOpen && (
        <div style={{ position:"fixed", top:0, right:0, bottom:0, width:420, background:"#fff", boxShadow:"-10px 0 40px rgba(11,31,94,0.12)", zIndex:9999, display:"flex", flexDirection:"column", animation:"dl-fade 0.2s ease" }}>
          {/* Header */}
          <div style={{ padding:"16px 20px", borderBottom:"1px solid var(--line)", display:"flex", justifyContent:"space-between", alignItems:"center", background:"var(--navy)", color:"#fff", flexShrink:0 }}>
            <div style={{ display:"flex", alignItems:"center", gap:10 }}>
              <div style={{ width:32, height:32, borderRadius:8, background:"rgba(255,255,255,0.12)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:16 }}>✨</div>
              <div>
                <div style={{ fontWeight:700, fontSize:14 }}>Vinpro Intelligence</div>
                <div style={{ fontSize:11, opacity:0.65, marginTop:1 }}>Powered by Claude</div>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} style={{ background:"transparent", border:"none", color:"#fff", cursor:"pointer", fontSize:18, lineHeight:1, opacity:0.7 }}>✕</button>
          </div>

          {/* Messages */}
          <div style={{ flex:1, padding:"16px 18px", overflowY:"auto", display:"flex", flexDirection:"column", gap:14, background:"var(--paper-2)" }}>
            {messages.map((m, i) => (
              <div key={i} style={{ display:"flex", flexDirection:"column", alignItems: m.role === "user" ? "flex-end" : "flex-start", gap:4 }}>
                {m.role === "assistant" && <div style={{ fontSize:10.5, fontWeight:600, color:"var(--text-3)", letterSpacing:"0.06em", marginLeft:2 }}>VINPRO AI</div>}
                <div style={{ background: m.role === "user" ? "var(--navy)" : "#fff", color: m.role === "user" ? "#fff" : "var(--navy)", padding:"10px 14px", borderRadius: m.role === "user" ? "12px 12px 4px 12px" : "12px 12px 12px 4px", border: m.role === "assistant" ? "1px solid var(--line)" : "none", maxWidth:"90%", fontSize:13.5, lineHeight:1.6, whiteSpace:"pre-wrap", wordBreak:"break-word" }}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div style={{ display:"flex", alignItems:"center", gap:8, padding:"8px 14px", background:"#fff", border:"1px solid var(--line)", borderRadius:"12px 12px 12px 4px", width:"fit-content" }}>
                <div style={{ display:"flex", gap:4 }}>
                  {[0,1,2].map(i => <div key={i} style={{ width:6, height:6, borderRadius:"50%", background:"var(--teal)", animation:`skeleton-loading 1.2s ease ${i*0.2}s infinite` }} />)}
                </div>
                <span style={{ fontSize:12, color:"var(--text-3)" }}>Thinking…</span>
              </div>
            )}
            {error && <div style={{ padding:"10px 14px", background:"var(--red-soft)", color:"var(--red)", borderRadius:10, fontSize:13 }}>{error}</div>}
            <div ref={messagesEndRef} />
          </div>

          {/* Quick prompts (shown only at start) */}
          {messages.length <= 1 && (
            <div style={{ padding:"0 18px 12px", display:"flex", flexDirection:"column", gap:6, flexShrink:0 }}>
              <div style={{ fontSize:11, fontWeight:700, color:"var(--text-3)", letterSpacing:"0.08em", textTransform:"uppercase", marginBottom:2 }}>Quick prompts</div>
              {QUICK_PROMPTS.map(p => (
                <button key={p} onClick={() => { setInput(p); }} style={{ padding:"8px 12px", borderRadius:8, border:"1px solid var(--line)", background:"#fff", color:"var(--navy)", fontSize:12.5, fontWeight:500, cursor:"pointer", textAlign:"left", fontFamily:"inherit", transition:"all 120ms" }}>
                  {p}
                </button>
              ))}
            </div>
          )}

          {/* Input */}
          <div style={{ padding:14, borderTop:"1px solid var(--line)", display:"flex", gap:8, flexShrink:0, background:"#fff" }}>
            <textarea
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Ask about payroll, compliance, HR drafts…"
              rows={2}
              style={{ flex:1, padding:"10px 12px", borderRadius:8, border:"1px solid var(--line-2)", outline:"none", resize:"none", fontFamily:"inherit", fontSize:13.5, lineHeight:1.5, color:"var(--navy)" }}
            />
            <button
              onClick={handleSend}
              disabled={isTyping || !input.trim()}
              style={{ padding:"10px 14px", background:"var(--navy)", color:"#fff", border:"none", borderRadius:8, cursor:"pointer", fontWeight:600, alignSelf:"flex-end", flexShrink:0 }}
            >
              ↑
            </button>
          </div>
        </div>
      )}
    </>
  );
}

// 5. Presenter Tools (God Mode)
const PRESENTER_PIN = "vinpro2026";

function DemoPresenterTools({ role, setRole, data, setData }) {
  const [open, setOpen] = useState(false);
  const [unlocked, setUnlocked] = useState(false);
  const [pinInput, setPinInput] = useState("");
  const [pinError, setPinError] = useState(false);

  function handleRoleSwitch(nextRole) {
    if (nextRole === "client") {
      // Bug C fix: ensure selectedClientCompanyId is a valid active client
      // before switching so ClientPortalDashboard never receives client = null
      const activeClients = (data.foreignClients || []).filter(c => c.portalStatus === "active");
      const alreadyValid = activeClients.some(c => c.id === data.selectedClientCompanyId);
      if (!alreadyValid && activeClients.length > 0) {
        setData(prev => ({ ...prev, selectedClientCompanyId: activeClients[0].id }));
      }
    }
    setRole(nextRole);
  }

  // Show button only when hovering the bottom-left corner for 1.5s — keeps demo clean
  const [showTrigger, setShowTrigger] = React.useState(false);
  const hoverTimer = React.useRef(null);
  if (!open) return (
    <div
      onMouseEnter={() => { hoverTimer.current = setTimeout(() => setShowTrigger(true), 1200); }}
      onMouseLeave={() => { clearTimeout(hoverTimer.current); setShowTrigger(false); }}
      style={{ position:"fixed", bottom:0, left:0, width:80, height:80, zIndex:9999 }}
    >
      {showTrigger && (
        <button onClick={() => setOpen(true)} style={{ position:"absolute", bottom:16, left:16, background:"rgba(8,14,44,0.7)", color:"#fff", padding:"6px 10px", borderRadius:8, fontSize:11, border:"none", cursor:"pointer", backdropFilter:"blur(4px)" }}>
          ⚙️
        </button>
      )}
    </div>
  );

  if (!unlocked) {
    return (
      <div style={{ position:"fixed", bottom:24, left:24, background:"#fff", padding:16, borderRadius:12, boxShadow:"var(--shadow-lg)", border:"1px solid var(--line)", zIndex:9999, display:"flex", flexDirection:"column", gap:10, width:220 }}>
        <div style={{ fontSize:11, textTransform:"uppercase", fontWeight:700, color:"var(--text-3)", display:"flex", justifyContent:"space-between" }}>
          <span>Presenter Menu</span>
          <button onClick={()=>setOpen(false)} style={{ background:"none", border:"none", cursor:"pointer" }}>✕</button>
        </div>
        <div style={{ fontSize:12, color:"var(--text-2)" }}>Enter PIN to unlock</div>
        <input
          type="password"
          value={pinInput}
          onChange={e => { setPinInput(e.target.value); setPinError(false); }}
          onKeyDown={e => {
            if (e.key === "Enter") {
              if (pinInput === PRESENTER_PIN) { setUnlocked(true); setPinInput(""); }
              else { setPinError(true); setPinInput(""); }
            }
          }}
          placeholder="Enter PIN…"
          style={{ padding:"7px 10px", borderRadius:8, border:`1px solid ${pinError?"var(--red)":"var(--line-2)"}`, fontSize:13, fontFamily:"inherit", outline:"none" }}
        />
        {pinError && <div style={{ fontSize:11.5, color:"var(--red)" }}>Incorrect PIN</div>}
        <button className="dl-btn dl-btn-primary dl-btn-sm" onClick={() => {
          if (pinInput === PRESENTER_PIN) { setUnlocked(true); setPinInput(""); }
          else { setPinError(true); setPinInput(""); }
        }}>Unlock</button>
      </div>
    );
  }

  return (
    <div style={{ position:"fixed", bottom:24, left:24, background:"#fff", padding:16, borderRadius:12, boxShadow:"var(--shadow-lg)", border:"1px solid var(--line)", zIndex:9999, display:"flex", flexDirection:"column", gap:10, width:220 }}>
      <div style={{ fontSize:11, textTransform:"uppercase", fontWeight:700, color:"var(--text-3)", display:"flex", justifyContent:"space-between" }}>
        <span>Presenter Menu 🔓</span>
        <button onClick={()=>{ setOpen(false); setUnlocked(false); }} style={{ background:"none", border:"none", cursor:"pointer" }}>✕</button>
      </div>
      <select value={role} onChange={(e) => handleRoleSwitch(e.target.value)} className="dl-input" style={{ fontSize:12, padding:6 }}>
        <option value="admin">View as: Super Admin</option>
        <option value="employer">View as: Employer</option>
        <option value="client">View as: Client</option>
        <option value="employee">View as: Employee</option>
        <option value="contractor">View as: Contractor</option>
      </select>
      <button className="dl-btn dl-btn-danger dl-btn-sm" onClick={() => {
        resetPersistedState();
        window.location.reload();
      }}>
        🔄 Reset Demo State
      </button>
    </div>
  );
}

// 6. Interactive Recharts Attendance Trend Chart — driven from real data
// NOTE: do NOT destructure at module load time — window.Recharts may not yet
// be available (CDN script tag races with bundle). We resolve lazily at render.
let BarChart, Bar, CartesianGrid, Legend;
function ensureRechartsBindings(){
  if (!window.Recharts) return false;
  const R = window.Recharts;
  BarChart      = BarChart      || R.BarChart;
  Bar           = Bar           || R.Bar;
  CartesianGrid = CartesianGrid || R.CartesianGrid;
  Legend        = Legend        || R.Legend;
  // Reseat the area-chart family too — same race condition applies.
  AreaChart         = AreaChart         || R.AreaChart;
  Area              = Area              || R.Area;
  XAxis             = XAxis             || R.XAxis;
  YAxis             = YAxis             || R.YAxis;
  Tooltip           = Tooltip           || R.Tooltip;
  ResponsiveContainer = ResponsiveContainer || R.ResponsiveContainer;
  return Boolean(BarChart && Bar && CartesianGrid && Legend && ResponsiveContainer);
}

function AttendanceTrendChart({ data }) {
  const [view, setView] = useState("week"); // "week" | "month"

  // Derive chart data from real attendance records
  const chartData = useMemo(() => {
    const records = data?.attendance || [];
    if (records.length === 0) return [];

    if (view === "week") {
      // Group by day-of-week for the most recent full week in data
      const dayNames = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
      const byDay = {};
      dayNames.forEach(d => { byDay[d] = { present:0, late:0, absent:0 }; });
      // Use last 7 days of data
      const sortedDates = [...new Set(records.map(r => r.date))].sort().slice(-7);
      sortedDates.forEach(date => {
        const dayRecs = records.filter(r => r.date === date);
        const dow = dayNames[new Date(date).getDay()];
        dayRecs.forEach(r => {
          if (r.status === "present") byDay[dow].present++;
          else if (r.status === "late") byDay[dow].late++;
          else if (r.status === "absent") byDay[dow].absent++;
        });
      });
      return sortedDates.map(date => {
        const dow = dayNames[new Date(date).getDay()];
        return { name: dow, date, ...byDay[dow] };
      });
    } else {
      // Group by date for last 20 working days
      const dates = [...new Set(records.map(r => r.date))].sort().slice(-20);
      return dates.map(date => {
        const dayRecs = records.filter(r => r.date === date);
        return {
          name: date.slice(5), // MM-DD
          present: dayRecs.filter(r => r.status === "present").length,
          late: dayRecs.filter(r => r.status === "late").length,
          absent: dayRecs.filter(r => r.status === "absent").length,
        };
      });
    }
  }, [data?.attendance, view]);

  const totalPresent = (data?.attendance || []).filter(r => r.status === "present").length;
  const totalLate    = (data?.attendance || []).filter(r => r.status === "late").length;
  const totalAbsent  = (data?.attendance || []).filter(r => r.status === "absent").length;
  const total = totalPresent + totalLate + totalAbsent || 1;
  const pctPresent = Math.round((totalPresent / total) * 100);

  const rechartsReady = ensureRechartsBindings();
  if (!rechartsReady) {
    // Graceful fallback — don't show an infinite loading gradient; show a
    // real summary card so the dashboard still feels complete.
    return (
      <div className="dl-card" style={{ padding:20, marginBottom:20 }}>
        <div className="dl-h2">Attendance Trends</div>
        <div style={{ fontSize:12.5, color:"var(--text-2)", marginTop:6 }}>
          Overall present rate: <strong style={{ color:"var(--teal)" }}>{pctPresent}%</strong>
          <span style={{ marginLeft:12 }}>🟢 {totalPresent} present · 🟡 {totalLate} late · 🔴 {totalAbsent} absent</span>
        </div>
        <div style={{ marginTop:14, display:"flex", gap:8, height:14, borderRadius:999, overflow:"hidden", background:"var(--paper-3)" }}>
          <div style={{ width:`${(totalPresent/total)*100}%`, background:"#2EBD9A" }}/>
          <div style={{ width:`${(totalLate/total)*100}%`,    background:"#F7C544" }}/>
          <div style={{ width:`${(totalAbsent/total)*100}%`,  background:"#FDA29B" }}/>
        </div>
        <div style={{ fontSize:11.5, color:"var(--text-3)", marginTop:10 }}>Charts library not loaded — showing summary view.</div>
      </div>
    );
  }

  return (
    <div className="dl-card" style={{ padding:20, display:"flex", flexDirection:"column", marginBottom:20 }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:16, flexWrap:"wrap", gap:10 }}>
        <div>
          <div className="dl-h2">Attendance Trends</div>
          <div style={{ fontSize:12.5, color:"var(--text-2)", marginTop:3 }}>
            Overall present rate: <strong style={{ color:"var(--teal)" }}>{pctPresent}%</strong>
            <span style={{ marginLeft:12 }}>🟢 {totalPresent} present · 🟡 {totalLate} late · 🔴 {totalAbsent} absent</span>
          </div>
        </div>
        <div style={{ display:"flex", gap:6 }}>
          {["week","month"].map(v => (
            <button key={v} onClick={() => setView(v)} style={{ padding:"5px 12px", borderRadius:8, border:"1px solid var(--line-2)", background: view===v ? "var(--navy)" : "#fff", color: view===v ? "#fff" : "var(--text-2)", fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:"inherit" }}>
              {v === "week" ? "By day" : "Last 20 days"}
            </button>
          ))}
        </div>
      </div>
      {chartData.length === 0 ? (
        <div style={{ height:200, display:"flex", alignItems:"center", justifyContent:"center", color:"var(--text-3)", fontSize:13 }}>No attendance records available.</div>
      ) : (
        <div style={{ height:220 }}>
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} barSize={18} barGap={3}>
              <defs>
                <linearGradient id="gradPresent" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="#2EBD9A" stopOpacity={0.95}/>
                  <stop offset="100%" stopColor="#2EBD9A" stopOpacity={0.6}/>
                </linearGradient>
              </defs>
              <CartesianGrid vertical={false} stroke="var(--line)" strokeDasharray="4 4" />
              <XAxis dataKey="name" tick={{ fontSize:11.5, fill:"var(--text-3)" }} axisLine={false} tickLine={false} />
              <YAxis tick={{ fontSize:11, fill:"var(--text-3)" }} axisLine={false} tickLine={false} width={24} />
              <Tooltip
                contentStyle={{ borderRadius:10, border:"1px solid var(--line)", boxShadow:"var(--shadow-md)", fontSize:12.5 }}
                cursor={{ fill:"var(--paper-3)" }}
              />
              <Legend iconType="circle" iconSize={8} wrapperStyle={{ fontSize:12, paddingTop:8 }} />
              <Bar dataKey="present" name="Present" fill="url(#gradPresent)" radius={[4,4,0,0]} />
              <Bar dataKey="late"    name="Late"    fill="#F7C544" radius={[4,4,0,0]} />
              <Bar dataKey="absent"  name="Absent"  fill="#FDA29B" radius={[4,4,0,0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
}

// ─── UTILITY ────────────────────────────────────────────────────────────────
const cn = (...xs) => xs.filter(Boolean).join(" ");
// today as live getter — protects against crossing midnight in long sessions
function getToday(){ return new Date().toISOString().slice(0, 10); }
const today = getToday();


// ─── CLIENT ONBOARDING ENGINE ──────────────────────────────────────────────

const PRODUCT_SCOPE_NOTE = "Payroll engine, contracts, and contractor management are intentionally out of scope in this prototype. Payslips, CTC structure, and salary revision views remain for later integration.";
const CLIENT_ONBOARDING_STAGES = [
  "created",
  "kyb_pending",
  "kyb_review",
  "kyb_approved",
  "msa_draft",
  "msa_sent",
  "msa_signed",
  "portal_provisioning",
  "portal_active"
];

function getClientUserStatus(user, client){
  if (user?.status) return user.status;
  if (client?.portalStatus === "active") return "active";
  if (client?.portalStatus === "provisioning" || client?.portalStatus === "processing") return "invited";
  return "draft";
}

function canClientAccessPortal(client, clientUser){
  if (!client || !clientUser) return false;
  const activeStage = client.onboardingStage === "portal_active" || client.onboardingStage === "active";
  const activeUser = getClientUserStatus(clientUser, client) === "active";
  return client.portalStatus === "active" && activeStage && activeUser;
}

function appendAuditLog(prev, { actor = "Admin", action, entity, module = "Client Onboarding" }){
  return [
    {
      id: `a-${Date.now()}-${Math.random().toString(36).slice(2,6)}`,
      actor,
      action,
      entity,
      module,
      time: today
    },
    ...(prev.auditLogsUI || [])
  ];
}

function getClientOnboardingIndex(stage){
  const stages = ["kyb_pending", "kyb_review", "kyb_approved", "msa_sent", "msa_signed", "portal_provisioning", "portal_active"];
  const normalized = stage === "active" ? "portal_active" : stage;
  return Math.max(0, stages.indexOf(normalized));
}

// ─── GLOBAL TOAST SYSTEM ────────────────────────────────────────────────────
const ToastCtx = React.createContext({ show: () => {} });
function ToastHost({ children }){
  const [items, setItems] = useState([]);
  const show = useCallback((msg, type = "info", ms = 3200) => {
    const id = `t-${Date.now()}-${Math.random().toString(36).slice(2,6)}`;
    setItems(prev => [...prev, { id, msg, type }]);
    setTimeout(() => setItems(prev => prev.filter(t => t.id !== id)), ms);
  }, []);
  const ctx = useMemo(() => ({ show }), [show]);
  return (
    <ToastCtx.Provider value={ctx}>
      {children}
      <div className="vp-toast-wrap" role="status" aria-live="polite">
        {items.map(t => (
          <div key={t.id} className={`vp-toast ${t.type}`}>
            <span style={{fontSize:16,lineHeight:1}}>
              {t.type === "success" ? "✓" : t.type === "error" ? "⚠" : t.type === "warning" ? "!" : "ℹ"}
            </span>
            <span style={{flex:1}}>{t.msg}</span>
          </div>
        ))}
      </div>
    </ToastCtx.Provider>
  );
}
function useToast(){ return React.useContext(ToastCtx); }

// ─── ERROR BOUNDARY ─────────────────────────────────────────────────────────
class ErrorBoundary extends React.Component {
  constructor(props){ super(props); this.state = { err: null }; }
  static getDerivedStateFromError(err){ return { err }; }
  componentDidCatch(err, info){ /* swallow in prototype */ }
  reset = () => this.setState({ err: null });
  render(){
    if(this.state.err){
      return (
        <div style={{minHeight:"60vh",display:"flex",alignItems:"center",justifyContent:"center",padding:32}}>
          <div style={{maxWidth:560,padding:"28px 32px",borderRadius:18,background:"#fff",border:"1px solid #DDE3F0",boxShadow:"0 18px 40px rgba(2,6,23,0.08)",textAlign:"center"}}>
            <div style={{fontSize:40,marginBottom:12}}>⚠️</div>
            <div style={{fontSize:18,fontWeight:700,color:"#0B1F5E",marginBottom:8}}>Something went wrong in this view</div>
            <div style={{fontSize:13.5,color:"#5A6A8A",marginBottom:18,lineHeight:1.6}}>
              {String(this.state.err?.message || this.state.err || "Unknown error")}
            </div>
            <button onClick={this.reset} style={{padding:"11px 22px",borderRadius:12,border:"none",background:"#0B1F5E",color:"#fff",fontWeight:700,cursor:"pointer",fontSize:13.5}}>Reload this view</button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

// ─── PERSISTENT STORAGE (artifact storage API → localStorage fallback) ────────
// v3 — bumped to discard cached state from prior builds so new defaults
// take effect: Employer EOR-section removal, dashboard Recharts lazy binding,
// asset permissions scoping, and asset retirement modal.
const PERSIST_KEY = "vinpro_demo_state_v3";

// Debounced async save
let _persistTimer = null;
function persistState(state){
  clearTimeout(_persistTimer);
  _persistTimer = setTimeout(async () => {
    try {
      const serialised = JSON.stringify(state);
      if (window.storage) {
        await window.storage.set(PERSIST_KEY, serialised);
      } else {
        window.localStorage.setItem(PERSIST_KEY, serialised);
      }
    } catch(e) {}
  }, 800);
}

// Async load (called on mount via useEffect)
async function loadPersistedStateAsync(){
  try {
    if (window.storage) {
      const result = await window.storage.get(PERSIST_KEY);
      if (result && result.value) {
        const parsed = JSON.parse(result.value);
        if (parsed && typeof parsed === "object") return parsed;
      }
    } else {
      const raw = window.localStorage.getItem(PERSIST_KEY);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (parsed && typeof parsed === "object") return parsed;
      }
    }
  } catch(e) {}
  return null;
}

// Sync load (quick-start from localStorage only)
function loadPersistedState(){
  try{
    const raw = window.localStorage.getItem(PERSIST_KEY);
    if(!raw) return null;
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === "object" ? parsed : null;
  }catch{ return null; }
}
function resetPersistedState(){
  try{
    if (window.storage) { window.storage.delete(PERSIST_KEY); }
    window.localStorage.removeItem(PERSIST_KEY);
  }catch{}
}

const CONNECT_LOGO = "data:image/png;base64,"
const EMPTY_PHOTO = "data:image/svg+xml;utf8," + encodeURIComponent(`<svg xmlns="http://www.w3.org/2000/svg" width="240" height="240" viewBox="0 0 240 240"><rect width="240" height="240" rx="24" fill="#EEF2F9"/><circle cx="120" cy="88" r="38" fill="#CBD5E1"/><path d="M48 206c9-40 34-64 72-64s63 24 72 64" fill="#CBD5E1"/></svg>`);

function fileToDataUrl(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

function addMonthsToDate(dateString, months) {
  if (!dateString) return "";
  const d = new Date(dateString);
  d.setMonth(d.getMonth() + Number(months || 0));
  return d.toISOString().slice(0, 10);
}

function formatDate(d) {
  if (!d) return "—";
  return new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" });
}
function getCompanyEmailDomain(employer) {
  const email = employer?.organisationProfile?.communicationEmail || employer?.organisationProfile?.registeredEmail || employer?.organisationProfile?.authorisedSignatory?.signatoryEmail || "";
  return email.includes("@") ? email.split("@")[1].toLowerCase() : "company.com";
}
function generateOfficialEmail(name, employer) {
  const parts = String(name || "").toLowerCase().replace(/[^a-z0-9 ]+/g, " ").trim().split(/\s+/).filter(Boolean);
  if (!parts.length) return "";
  const local = parts.length === 1 ? parts[0] : `${parts[0]}.${parts[parts.length - 1]}`;
  return `${local}@${getCompanyEmailDomain(employer)}`;
}
const HRA_METRO_CITIES = ["Delhi", "Mumbai", "Kolkata", "Chennai"];
function addDaysToDate(dateString, days) {
  const base = dateString ? new Date(dateString) : new Date();
  const next = new Date(base.getTime() + (Number(days || 0) * 24 * 60 * 60 * 1000));
  return next.toISOString().slice(0, 10);
}
function fyFromDate(dateValue) {
  const ref = dateValue ? new Date(dateValue) : new Date();
  const year = ref.getMonth() + 1 >= 4 ? ref.getFullYear() : ref.getFullYear() - 1;
  return `${year}-${String((year + 1)).slice(-2)}`;
}
function isMetroHraCity(city) {
  const target = String(city || "").trim().toLowerCase();
  return HRA_METRO_CITIES.some(entry => entry.toLowerCase() === target);
}
function getOfferLocationContext(offer, employer) {
  const org = employer?.organisationProfile || {};
  const branches = org.branches || [];
  const headOffice = branches[0] || { branchName:"Head Office", city:org.city || org.registeredOfficeCity || "", state:org.state || org.registeredOfficeState || "", address:org.registeredAddress || org.companyAddress || "" };
  if ((offer?.workLocationType || "hq") === "branch") {
    const branch = branches.find(entry => entry.id === offer?.branchId) || branches.find(entry => !/head office/i.test(entry.branchName || "")) || headOffice;
    return {
      type: "branch",
      label: branch?.branchName || "Branch",
      city: branch?.city || org.city || "",
      state: branch?.state || org.state || "",
      address: branch?.address || org.registeredAddress || org.companyAddress || "",
      isMetro: isMetroHraCity(branch?.city),
      metroCategory: isMetroHraCity(branch?.city) ? "Metro" : "Non-Metro"
    };
  }
  return {
    type: offer?.workLocationType === "remote" ? "remote" : "hq",
    label: offer?.workLocationType === "remote" ? "Remote (HQ rules)" : "HQ",
    city: headOffice?.city || org.city || "",
    state: headOffice?.state || org.state || "",
    address: headOffice?.address || org.registeredAddress || org.companyAddress || "",
    isMetro: true,
    metroCategory: "Metro"
  };
}
function calculateRecruitmentCtcEngine(input, employer) {
  const annualFixedCtc = Math.max(0, Math.round(Number(input?.annualFixedCtc || 0)));
  const annualVariablePay = Math.max(0, Math.round(Number(input?.annualVariablePay || 0)));
  const location = getOfferLocationContext(input, employer);
  const monthlyFixedCtc = Math.round(annualFixedCtc / 12);
  const basicMonthly = Math.round(monthlyFixedCtc * 0.5);
  const hraMonthly = Math.round(basicMonthly * (location.isMetro ? 0.5 : 0.4));
  const employerEpfMonthly = Math.round(Math.min(basicMonthly, 15000) * 0.12);
  const gratuityMonthly = Math.round(basicMonthly * 0.0481);
  const specialAllowanceMonthly = Math.max(0, Math.round(monthlyFixedCtc - (basicMonthly + hraMonthly + employerEpfMonthly + gratuityMonthly)));
  const employerContributionMonthly = employerEpfMonthly + gratuityMonthly;
  const variablePayMonthly = Math.round(annualVariablePay / 12);
  const annualEmployerContribution = employerContributionMonthly * 12;
  const totalFixedCtcMonthly = monthlyFixedCtc + employerContributionMonthly;
  const totalFixedCtcAnnual = annualFixedCtc + annualEmployerContribution;
  const totalTargetCompMonthly = totalFixedCtcMonthly + variablePayMonthly;
  const totalTargetCompAnnual = totalFixedCtcAnnual + annualVariablePay;
  return {
    location,
    metroCategory: location.metroCategory,
    annualFixedCtc,
    monthlyFixedCtc,
    basicMonthly,
    basicAnnual: basicMonthly * 12,
    hraMonthly,
    hraAnnual: hraMonthly * 12,
    employerEpfMonthly,
    employerEpfAnnual: employerEpfMonthly * 12,
    gratuityMonthly,
    gratuityAnnual: gratuityMonthly * 12,
    specialAllowanceMonthly,
    specialAllowanceAnnual: specialAllowanceMonthly * 12,
    annualEmployerContribution,
    employerContributionMonthly,
    annualVariablePay,
    variablePayMonthly,
    totalFixedCtcMonthly,
    totalFixedCtcAnnual,
    totalTargetCompMonthly,
    totalTargetCompAnnual
  };
}
function buildCompensationStructureFromPayrollConfig(config, employeeId, employerId, effectiveFrom) {
  return {
    id:`ctc-${Date.now()}`,
    employeeId,
    employerId,
    financialYear: fyFromDate(effectiveFrom || today),
    effectiveFrom: effectiveFrom || today,
    annualFixedGross: Number(config?.annualFixedCtc || 0),
    monthlyFixedGross: Number(config?.monthlyFixedCtc || 0),
    pfEmployer: Number(config?.employerEpfMonthly || 0),
    esiEmployer: 0,
    gratuity: Number(config?.gratuityMonthly || 0),
    medicalInsurance: 0,
    variablePayAnnual: Number(config?.annualVariablePay || 0),
    components: [
      { label:"Basic Pay", monthly:Number(config?.basicMonthly || 0), yearly:Number(config?.basicAnnual || 0) },
      { label:"House Rent Allowance", monthly:Number(config?.hraMonthly || 0), yearly:Number(config?.hraAnnual || 0) },
      { label:"Other Allowance", monthly:Number(config?.specialAllowanceMonthly || 0), yearly:Number(config?.specialAllowanceAnnual || 0) }
    ],
    deductions: [],
    agreementLinked: true,
    ctcEngine: "location_aware_annexure"
  };
}
function getEmployeePayrollConfig(data, employee) {
  if (!employee) return null;
  const direct = employee.payroll_config || employee.payrollConfig;
  if (direct) return direct;
  const structures = (data?.compensationStructures || []).filter(item => item.employeeId === employee.id).sort((a, b) => String(b.effectiveFrom || "").localeCompare(String(a.effectiveFrom || "")));
  const structure = structures[0];
  if (!structure) return null;
  const components = {};
  (structure.components || []).forEach(item => { if (item?.label) components[item.label] = item; });
  const basicMonthly = Number(components["Basic Pay"]?.monthly || 0);
  const hraMonthly = Number(components["House Rent Allowance"]?.monthly || components["HRA"]?.monthly || 0);
  const specialAllowanceMonthly = Number(components["Special Allowance"]?.monthly || components["Other Allowance"]?.monthly || 0);
  const employerEpfMonthly = Number(structure.pfEmployer || 0);
  const gratuityMonthly = Number(structure.gratuity || 0);
  const annualFixedCtc = Number(structure.annualFixedGross || 0);
  const monthlyFixedCtc = Number(structure.monthlyFixedGross || Math.round(annualFixedCtc / 12) || 0);
  const annualVariablePay = Number(structure.variablePayAnnual || 0);
  const employerContributionMonthly = employerEpfMonthly + gratuityMonthly;
  const annualEmployerContribution = employerContributionMonthly * 12;
  return {
    annualFixedCtc,
    monthlyFixedCtc,
    basicMonthly,
    basicAnnual: basicMonthly * 12,
    hraMonthly,
    hraAnnual: hraMonthly * 12,
    specialAllowanceMonthly,
    specialAllowanceAnnual: specialAllowanceMonthly * 12,
    employerEpfMonthly,
    employerEpfAnnual: employerEpfMonthly * 12,
    gratuityMonthly,
    gratuityAnnual: gratuityMonthly * 12,
    annualVariablePay,
    variablePayMonthly: Math.round(annualVariablePay / 12),
    annualEmployerContribution,
    employerContributionMonthly,
    totalFixedCtcMonthly: monthlyFixedCtc + employerContributionMonthly,
    totalFixedCtcAnnual: annualFixedCtc + annualEmployerContribution,
    totalTargetCompMonthly: monthlyFixedCtc + employerContributionMonthly + Math.round(annualVariablePay / 12),
    totalTargetCompAnnual: annualFixedCtc + annualEmployerContribution + annualVariablePay,
    location: { type:"existing", label: employee.workLocation || "HQ", city:(employee.workLocation || "").split(",")[0] || "", state:(employee.workLocation || "").split(",").slice(-1)[0] || "", address: employee.workLocation || "", isMetro: true, metroCategory: "Metro" }
  };
}
function getDefaultDesignationKpis(designation, employerId) {
  const label = String(designation || "General").toLowerCase();
  const catalogue = label.includes("finance") ? [
    ["Accuracy & Compliance", "Deliver error-free outputs and statutory accuracy across finance activities."],
    ["Client Delivery", "Meet timelines and provide dependable client-ready deliverables."],
    ["Stakeholder Responsiveness", "Respond to internal and external stakeholders on time with clarity."],
    ["Process Improvement", "Identify and implement improvements in finance workflows and controls."],
    ["Collaboration & Ownership", "Demonstrate ownership, teamwork, and escalation discipline."]
  ] : label.includes("engineer") || label.includes("developer") ? [
    ["Engineering Output", "Deliver sprint commitments with reliable execution quality."],
    ["Code Quality", "Maintain testing, review quality, documentation, and maintainability."],
    ["Problem Solving", "Diagnose production and development issues with structured analysis."],
    ["Process Improvement", "Contribute automation, tooling, and architecture improvements."],
    ["Collaboration", "Work effectively with product, QA, and cross-functional teams."]
  ] : [
    ["Role Delivery", "Deliver the core expectations of the role consistently and accurately."],
    ["Quality", "Maintain output quality, documentation, and compliance discipline."],
    ["Timeliness", "Meet timelines and communicate proactively on dependencies and risks."],
    ["Improvement", "Drive continuous improvement and operational efficiency."],
    ["Collaboration", "Demonstrate teamwork, ownership, and stakeholder partnership."]
  ];
  return catalogue.map((entry, index) => ({
    id:`tmpl-${normaliseKey(designation || "general")}-${index + 1}`,
    employerId,
    designation,
    title: entry[0],
    category: index < 2 ? "Core" : index === 2 ? "Behavioural" : "Improvement",
    description: entry[1],
    weight: 18,
    isPrimary: index === 0
  }));
}

