function getIcon(icon) {
  return ICONS[icon] || (
    <svg viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><line x1="3" y1="9" x2="21" y2="9"/><line x1="9" y1="21" x2="9" y2="9"/></svg>
  );
}

function StatCard({ title, value, icon, subtext, accent, imageUrl }) {
  const _str = String(value ?? "—");
  const isNum = typeof value === "number";
  const vLen = _str.length;
  const fontSize = isNum ? 22 : vLen > 22 ? 14 : vLen > 14 ? 17 : 22;
  return (
    <Card style={{ flex:1, minWidth:160, overflow:"hidden" }}>
      <CardContent style={{ padding:"16px", display:"flex", flexDirection:"column", gap:0 }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", gap:10 }}>
          <div style={{ fontSize:10.5, fontWeight:700, letterSpacing:"0.08em", textTransform:"uppercase", color:palette.muted, lineHeight:1.4, flex:1, minWidth:0, whiteSpace:"normal" }}>{title}</div>
          <div style={{ width:36, height:36, borderRadius:8, background:"var(--paper-3,#F4F6FB)", border:"1px solid var(--line,#E4E8F1)", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
            {imageUrl
              ? <img src={imageUrl} alt={title} style={{width:24,height:24,objectFit:"contain"}}/>
              : <svg viewBox="0 0 24 24" style={{width:18,height:18,stroke:accent||"#0B1F5E",opacity:0.6,strokeWidth:1.75,fill:"none",strokeLinecap:"round",strokeLinejoin:"round"}}>{getIcon(icon).props.children}</svg>
            }
          </div>
        </div>
        <div style={{ fontSize:fontSize, lineHeight:1.15, fontWeight:800, color:accent||palette.navy, letterSpacing:"-0.03em", marginTop:10, whiteSpace:"normal", wordBreak:"break-word" }}>{_str}</div>
        {subtext && <div style={{ fontSize:12, color:palette.muted, lineHeight:1.5, marginTop:6, whiteSpace:"normal" }}>{subtext}</div>}
      </CardContent>
    </Card>
  );
}
function Alert({ type = "info", children }) {
  const colors = { info:{bg:"#EFF6FF",border:"#BFDBFE",color:"#1E40AF",icon:"ℹ️"}, success:{bg:"#ECFDF5",border:"#A7F3D0",color:"#065F46",icon:"✅"}, warning:{bg:"#FFFBEB",border:"#FDE68A",color:"#92400E",icon:"⚠️"}, error:{bg:"#FEF2F2",border:"#FECACA",color:"#991B1B",icon:"🚨"} };
  const s = colors[type];
  return <div style={{ padding:"10px 14px", borderRadius:8, background:s.bg, border:`1px solid ${s.border}`, color:s.color, fontSize:13, lineHeight:1.6, display:"flex", gap:8, alignItems:"flex-start" }}><span style={{ flexShrink:0, fontSize:14 }}>{s.icon}</span><span>{children}</span></div>;
}
function Progress({ value }) {
  return <div style={{ height:6, borderRadius:100, background:"#E2E8F0", overflow:"hidden" }}><div style={{ height:"100%", width:`${Math.min(100,Math.max(0,value))}%`, background:value>=100?palette.teal:value>=60?palette.navy:palette.gold, borderRadius:100, transition:"width 0.5s ease" }}/></div>;
}
function SectionHeader({ title, subtitle, action }) {
  return <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:16, marginBottom:22, flexWrap:"wrap" }}><div style={{minWidth:0}}><h2 style={{ fontSize:20, fontWeight:700, color:palette.navy, margin:0, letterSpacing:"-0.03em", fontFamily:HEADING_STACK }}>{title}</h2>{subtitle && <p style={{ fontSize:14, color:palette.muted, margin:"6px 0 0", lineHeight:1.65, maxWidth:820 }}>{subtitle}</p>}</div>{action}</div>;
}
function EmptyState({ icon = "📭", message }) {
  return <div style={{ padding:"40px 16px", textAlign:"center", color:palette.muted }}><div style={{ fontSize:28 }}>{icon}</div><div style={{ marginTop:12, fontSize:13, lineHeight:1.65 }}>{message}</div></div>;
}
const labelStyle = { fontSize:12, fontWeight:600, color:palette.muted, display:"block", marginBottom:8, letterSpacing:"0.01em", textTransform:"none" };
const pillStyle = { display:"inline-block", padding:"3px 10px", borderRadius:100, background:palette.offwhite, fontSize:12, color:palette.muted };
function FormRow({ label, children }) {
  return <div>{label && <label style={labelStyle}>{label}</label>}{children}</div>;
}

function SimpleModal({ title, onClose, children, width = 980 }) {
  return (
    <div style={{position:"fixed",inset:0,zIndex:1200,background:"rgba(11,31,94,0.42)",display:"flex",alignItems:"center",justifyContent:"center",padding:24}} onClick={onClose}>
      <div onClick={e=>e.stopPropagation()} style={{width:"100%",maxWidth:width,maxHeight:"90vh",overflow:"hidden",display:"flex",flexDirection:"column",background:"#fff",borderRadius:20,boxShadow:"0 24px 80px rgba(2,6,23,0.2)"}}>
        <div style={{padding:"18px 22px",borderBottom:`1px solid ${palette.border}`,display:"flex",alignItems:"center",justifyContent:"space-between",gap:12,background:"#fff"}}>
          <div style={{fontSize:16,fontWeight:700,color:palette.navy}}>{title}</div>
          <button onClick={onClose} aria-label="Close dialog" style={{width:32,height:32,borderRadius:999,border:`1px solid ${palette.border}`,background:"#fff",cursor:"pointer",color:palette.navy}}>✕</button>
        </div>
        <div style={{padding:22,overflowY:"auto",display:"flex",flexDirection:"column",gap:16,background:palette.stage}}>{children}</div>
      </div>
    </div>
  );
}

function parseCsvRows(csvText) {
  const lines = String(csvText || "").replace(/\r/g, "").split("\n").filter(Boolean);
  if (!lines.length) return [];
  const parseLine = (line) => {
    const out = [];
    let current = "";
    let inQuotes = false;
    for (let i = 0; i < line.length; i += 1) {
      const ch = line[i];
      if (ch === '"') {
        if (inQuotes && line[i + 1] === '"') { current += '"'; i += 1; }
        else { inQuotes = !inQuotes; }
      } else if (ch === "," && !inQuotes) {
        out.push(current.trim());
        current = "";
      } else {
        current += ch;
      }
    }
    out.push(current.trim());
    return out.map(v => v.replace(/^"|"$/g, ""));
  };
  const headers = parseLine(lines[0]);
  return lines.slice(1).map(line => {
    const cells = parseLine(line);
    const row = {};
    headers.forEach((header, index) => { row[header] = cells[index] ?? ""; });
    return row;
  }).filter(row => Object.values(row).some(Boolean));
}

function downloadCsvFile(filename, columns, sampleRows = []) {
  const lines = [columns.join(",")].concat(sampleRows.map(row => columns.map(col => {
    const value = row[col] ?? "";
    const stringValue = String(value).replace(/"/g, '""');
    return /[",\n]/.test(stringValue) ? `"${stringValue}"` : stringValue;
  }).join(",")));
  const blob = new Blob([lines.join("\n")], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.click();
  setTimeout(() => URL.revokeObjectURL(url), 1200);
}

function normaliseMigrationStatus(value, fallback = "pending_documentation") {
  const raw = String(value || "").toLowerCase().trim().replace(/\s+/g, "_");
  const map = {
    pending_documentation:"pending_documentation",
    pending_docs:"pending_documentation",
    pending_onboarding:"pending_documentation",
    pending_agreement:"pending_agreement",
    agreement_pending:"pending_agreement",
    pending_employer_signature:"pending_employer_signature",
    pending_asset_mapping:"pending_asset_mapping",
    asset_pending:"pending_asset_mapping",
    active:"active",
    active_employee:"active",
    active_contractor:"active"
  };
  return map[raw] || fallback;
}

function getWorkerQueueBucket(worker) {
  if (!worker) return "pending_documentation";
  const stage = String(worker.onboardingStage || worker.status || "").toLowerCase();
  const agreementStatus = String(worker.agreementStatus || "").toLowerCase();
  const assetStatus = String(worker.assetStatus || "").toLowerCase();
  if (["pending_employer_signature"].includes(stage) || agreementStatus === "employee_signed") return "pending_employer_signature";
  if (["asset_assignment_pending", "pending_asset_mapping"].includes(stage) || ["pending_mapping","not_assigned"].includes(assetStatus)) return "pending_asset_mapping";
  if (["pending_agreement","agreement_pending"].includes(stage) || ["not_sent","sent","sent_to_employee"].includes(agreementStatus)) return "pending_agreement";
  if (["active"].includes(stage) || agreementStatus === "signed") return "active";
  return "pending_documentation";
}

function migrationStageToWorkerFields(status) {
  const normalised = normaliseMigrationStatus(status);
  if (normalised === "pending_agreement") return { onboardingStage:"pending_agreement", status:"pending_agreement", agreementStatus:"not_sent", progress:82 };
  if (normalised === "pending_employer_signature") return { onboardingStage:"pending_employer_signature", status:"pending_employer_signature", agreementStatus:"employee_signed", progress:95 };
  if (normalised === "pending_asset_mapping") return { onboardingStage:"asset_assignment_pending", status:"asset_assignment_pending", agreementStatus:"signed", progress:100 };
  if (normalised === "active") return { onboardingStage:"active", status:"active", agreementStatus:"signed", progress:100 };
  return { onboardingStage:"pending_documentation", status:"pending_documentation", agreementStatus:"not_sent", progress:68 };
}

function createAgreementRecordForWorker(worker, employer, kind = "employee") {
  const signed = String(worker.agreementStatus || "").toLowerCase() === "signed";
  const employeeSigned = String(worker.agreementStatus || "").toLowerCase() === "employee_signed";
  return {
    id:`ag-${Date.now()}-${Math.floor(Math.random()*1000)}`,
    employeeId: worker.id,
    employerId: employer.id,
    agreementType: kind === "contractor" ? "contractor" : "employment",
    status: signed ? "signed" : employeeSigned ? "sent" : "draft",
    agreementSigningStage: signed ? "fully_signed" : employeeSigned ? "sent_to_signatory" : "draft",
    employeeSignedAt: employeeSigned || signed ? today : null,
    signatorySignedAt: signed ? today : null,
    editorFields: {
      employeeName: worker.name,
      designation: worker.designation,
      email: worker.email,
      officialEmail: worker.officialEmail || worker.workEmail || "",
      phone: worker.phone || "",
      joiningDate: worker.joiningDate || today,
      workCity: String(worker.workLocation || "").split(",")[0] || "",
      workState: String(worker.workLocation || "").split(",")[1] || "",
      salaryCtc: String(worker.payroll_config?.totalTargetCompAnnual || worker.compensationAnnual || worker.contractorFee || 0)
    },
    additionalClauses: kind === "contractor" ? [{id:`cl-${Date.now()}`,title:"Legacy Contractor Import",body:"This contractor record was migrated into Connect by Vinpro through the direct add or bulk upload workflow."}] : [{id:`cl-${Date.now()}`,title:"Legacy Employee Import",body:"This employee record was migrated into Connect by Vinpro through the direct add or bulk upload workflow."}]
  };
}

function officialEmailExists(data, email, currentId = null) {
  const value = String(email || "").trim().toLowerCase();
  if (!value) return false;
  return (data.employees || []).some(emp => emp.id !== currentId && [emp.officialEmail, emp.workEmail].filter(Boolean).some(item => String(item).trim().toLowerCase() === value));
}

