function mergePersistedStateWithDefaults(persisted){
  if(!persisted) return initialData;
  const merged = { ...initialData, ...persisted };

  // ── employers (existing safe merge) ────────────────────────────────────────
  const persistedEmployers = Array.isArray(persisted.employers) ? persisted.employers : [];
  merged.employers = [
    ...(initialData.employers || []).map(base => {
      const existing = persistedEmployers.find(item => item.id === base.id);
      if(!existing) return base;
      return {
        ...base,
        ...existing,
        organisationProfile:{
          ...base.organisationProfile,
          ...(existing.organisationProfile || {}),
          enabledModules:(() => {
            // Strip EOR-operator modules from persisted Employer state — those
            // now belong exclusively to Admin. Prior versions shipped them on
            // the Employer tenant, so we scrub them on hydrate.
            const EOR_ADMIN_ONLY = new Set(["eor_dashboard","client_companies","eor_hire_requests","eor_workforce","eor_payroll_run","eor_statutory","eor_billing","eor_compliance"]);
            const persistedMods = Array.isArray(existing.organisationProfile?.enabledModules) ? existing.organisationProfile.enabledModules : [];
            const baseMods = base.organisationProfile?.enabledModules || [];
            const source = persistedMods.length ? persistedMods : baseMods;
            return source.filter(m => !EOR_ADMIN_ONLY.has(m));
          })(),
          performanceConfig:{
            ...(base.organisationProfile?.performanceConfig || {}),
            ...(existing.organisationProfile?.performanceConfig || {})
          }
        }
      };
    }),
    ...persistedEmployers.filter(item => !(initialData.employers || []).some(base => base.id === item.id))
  ];
  if(!merged.employers.some(entry => entry.id === merged.selectedEmployerId)){
    merged.selectedEmployerId = merged.employers[0]?.id || "";
  }

  // ── Bug A fix: foreignClients — always use seed baseline; never let persisted
  //    portalStatus / onboardingStage corrupt the client-access gate ───────────
  const persistedForeignClients = Array.isArray(persisted.foreignClients) ? persisted.foreignClients : [];
  merged.foreignClients = [
    ...(initialData.foreignClients || []).map(base => {
      const existing = persistedForeignClients.find(item => item.id === base.id);
      if(!existing) return base;
      return {
        ...base,
        ...existing,
        // Always restore portal-access fields from seed so the guard never breaks
        portalStatus: base.portalStatus,
        onboardingStage: base.onboardingStage,
      };
    }),
    ...persistedForeignClients.filter(item => !(initialData.foreignClients || []).some(base => base.id === item.id))
  ];

  // ── Bug B fix: clientUsers — if persisted array is empty (pre-buildEorSeed
  //    localStorage) fall back to seed data so matchedClientUser is never null ─
  const persistedClientUsers = Array.isArray(persisted.clientUsers) ? persisted.clientUsers : [];
  merged.clientUsers = persistedClientUsers.length > 0
    ? persistedClientUsers
    : (initialData.clientUsers || []);

  // ── Ensure selectedClientCompanyId points to a real, active client ──────────
  const activeClients = (merged.foreignClients || []).filter(c => c.portalStatus === "active");
  const selectedIsValid = activeClients.some(c => c.id === merged.selectedClientCompanyId);
  if(!selectedIsValid && activeClients.length > 0){
    merged.selectedClientCompanyId = activeClients[0].id;
  }

  return merged;
}


