// ── Firebase REST config ──────────────────────────────────────────────────────
// Replace these with your Firebase project values (no npm SDK needed)
const DEMO_FB_PROJECT = "YOUR_FIREBASE_PROJECT_ID";
const DEMO_FB_API_KEY = "YOUR_FIREBASE_API_KEY";
const DEMO_FB_BASE = `https://firestore.googleapis.com/v1/projects/${DEMO_FB_PROJECT}/databases/(default)/documents`;

async function fbGet(path) {
  try {
    const r = await fetch(`${DEMO_FB_BASE}/${path}?key=${DEMO_FB_API_KEY}`);
    if (!r.ok) return null;
    return await r.json();
  } catch { return null; }
}

async function fbPatch(path, fields) {
  try {
    const body = { fields: {} };
    for (const [k, v] of Object.entries(fields)) {
      if (typeof v === "string") body.fields[k] = { stringValue: v };
      else if (typeof v === "number") body.fields[k] = { integerValue: v };
      else if (typeof v === "boolean") body.fields[k] = { booleanValue: v };
      else body.fields[k] = { stringValue: JSON.stringify(v) };
    }
    const fieldPaths = Object.keys(fields).map(k => `updateMask.fieldPaths=${k}`).join("&");
    await fetch(`${DEMO_FB_BASE}/${path}?key=${DEMO_FB_API_KEY}&${fieldPaths}`, {
      method: "PATCH", headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body)
    });
  } catch { /* silently fail */ }
}

async function fbArrayAppend(tokenId, field, value) {
  // Firestore array append via REST
  try {
    await fetch(`${DEMO_FB_BASE}/tokens/${tokenId}:commit?key=${DEMO_FB_API_KEY}`, {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        writes: [{
          transform: {
            document: `projects/${DEMO_FB_PROJECT}/databases/(default)/documents/tokens/${tokenId}`,
            fieldTransforms: [{ fieldPath: field, appendMissingElements: { values: [{ stringValue: JSON.stringify(value) }] } }]
          }
        }]
      })
    });
  } catch { /* silently fail */ }
}

function parseFirestoreDoc(doc) {
  if (!doc || !doc.fields) return null;
  const out = {};
  for (const [k, v] of Object.entries(doc.fields)) {
    if (v.stringValue !== undefined) out[k] = v.stringValue;
    else if (v.integerValue !== undefined) out[k] = Number(v.integerValue);
    else if (v.booleanValue !== undefined) out[k] = v.booleanValue;
    else if (v.timestampValue !== undefined) out[k] = v.timestampValue;
    else out[k] = v;
  }
  return out;
}

