// ── DemoTourOverlay ────────────────────────────────────────────────────────────
function DemoTourOverlay({ navigateTo }) {
  const [step, setStep] = React.useState(null);
  const [spotlight, setSpotlight] = React.useState(null);
  const [tipPos, setTipPos] = React.useState({ top: 120, left: 260 });
  const [speaking, setSpeaking] = React.useState(false);
  const [showWelcome, setShowWelcome] = React.useState(false);

  // Expose start function globally so DemoShell can trigger it
  React.useEffect(() => {
    window.__vinproStartTour = () => setShowWelcome(true);
    return () => { delete window.__vinproStartTour; };
  }, []);

  const computeSpot = React.useCallback((sel) => {
    setTimeout(() => {
      const el = document.querySelector(sel);
      if (!el) return;
      const r = el.getBoundingClientRect();
      const pad = 8;
      setSpotlight({ top: r.top - pad, left: r.left - pad, w: r.width + pad * 2, h: r.height + pad * 2 });
      const TW = 320, TH = 230;
      let left = r.right + 20;
      let top = Math.max(12, r.top + r.height / 2 - TH / 2);
      if (left + TW > window.innerWidth - 12) left = r.left - TW - 20;
      if (left < 12) { left = Math.max(12, r.left); top = r.bottom + 16; }
      if (top + TH > window.innerHeight - 12) top = window.innerHeight - TH - 12;
      setTipPos({ top, left });
    }, 300);
  }, []);

  const speak = React.useCallback((text) => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const u = new SpeechSynthesisUtterance(text);
    u.rate = 0.93; u.pitch = 1.05;
    u.onstart = () => setSpeaking(true);
    u.onend = () => setSpeaking(false);
    u.onerror = () => setSpeaking(false);
    window.speechSynthesis.speak(u);
  }, []);

  const goStep = React.useCallback((idx) => {
    const s = DEMO_STEPS[idx];
    setStep(idx);
    if (s.nav && navigateTo) {
      navigateTo(s.nav);
      setTimeout(() => computeSpot(s.sel), 450);
    } else {
      computeSpot(s.sel);
    }
    speak(s.voice);
    if (window.__vinproLogEvent) window.__vinproLogEvent("tour_step", { step: idx, title: s.title });
  }, [computeSpot, speak, navigateTo]);

  const next = React.useCallback(() => {
    window.speechSynthesis?.cancel();
    if (step + 1 >= DEMO_STEPS.length) {
      setStep(null); setSpotlight(null); setSpeaking(false);
      if (window.__vinproLogEvent) window.__vinproLogEvent("tour_complete", {});
    } else { goStep(step + 1); }
  }, [step, goStep]);

  const prev = React.useCallback(() => {
    window.speechSynthesis?.cancel();
    if (step > 0) goStep(step - 1);
  }, [step, goStep]);

  const endTour = React.useCallback(() => {
    window.speechSynthesis?.cancel();
    setStep(null); setSpotlight(null); setSpeaking(false);
  }, []);

  const startTour = () => {
    setShowWelcome(false);
    goStep(0);
  };

  const cur = step !== null ? DEMO_STEPS[step] : null;

  return (
    <>
      {/* Welcome modal */}
      {showWelcome && (
        <div style={{ position:"fixed", inset:0, background:"rgba(11,31,94,0.82)", zIndex:19000, display:"flex", alignItems:"center", justifyContent:"center", backdropFilter:"blur(6px)" }}>
          <div style={{ background:"#fff", borderRadius:20, padding:40, maxWidth:420, width:"90%", textAlign:"center", boxShadow:"0 32px 80px rgba(11,31,94,0.22)" }}>
            <div style={{ width:64, height:64, background:"var(--teal)", borderRadius:18, display:"flex", alignItems:"center", justifyContent:"center", fontSize:26, margin:"0 auto 20px" }}>✨</div>
            <div style={{ fontSize:22, fontWeight:800, color:"var(--navy)", marginBottom:8, letterSpacing:"-0.02em" }}>Welcome to Vinpro Connect</div>
            <div style={{ fontSize:13.5, color:"var(--text-2)", lineHeight:1.75, marginBottom:32 }}>
              Enterprise HRMS built for Indian businesses.<br/>
              Take a guided tour with live narration, or explore freely.
            </div>
            <button onClick={startTour} style={{ display:"block", width:"100%", background:"var(--navy)", color:"#fff", fontWeight:700, fontSize:14, padding:"13px", borderRadius:12, border:"none", cursor:"pointer", marginBottom:10 }}>
              ▶  Start Guided Tour
            </button>
            <button onClick={() => setShowWelcome(false)} style={{ display:"block", width:"100%", background:"transparent", color:"var(--text-2)", fontSize:13, padding:"11px", borderRadius:12, border:"1px solid var(--line-2)", cursor:"pointer" }}>
              Explore on my own
            </button>
            <div style={{ marginTop:20, fontSize:11, color:"var(--text-3)" }}>🔊 Enable audio for narrated experience</div>
          </div>
        </div>
      )}

      {/* Spotlight + tooltip */}
      {step !== null && spotlight && (
        <>
          <div style={{ position:"fixed", inset:0, zIndex:17000, cursor:"default" }} onClick={e => e.stopPropagation()} />
          <div style={{ position:"fixed", top:spotlight.top, left:spotlight.left, width:spotlight.w, height:spotlight.h, boxShadow:"0 0 0 9999px rgba(11,31,94,0.72)", borderRadius:12, border:"2px solid var(--teal)", zIndex:17001, pointerEvents:"none", transition:"all 0.35s cubic-bezier(0.4,0,0.2,1)" }} />
          <div style={{ position:"fixed", top:tipPos.top, left:tipPos.left, width:320, background:"#fff", border:"1px solid var(--line)", borderRadius:16, padding:22, zIndex:17002, boxShadow:"0 20px 60px rgba(11,31,94,0.18)" }}>
            <div style={{ fontSize:10, fontWeight:700, color:"var(--teal-2)", textTransform:"uppercase", letterSpacing:"0.1em", marginBottom:8 }}>
              Step {step + 1} of {DEMO_STEPS.length}
              {speaking && <span style={{ marginLeft:10, opacity:0.7 }}>🔊 narrating…</span>}
            </div>
            <div style={{ fontSize:15, fontWeight:800, color:"var(--navy)", marginBottom:8, letterSpacing:"-0.01em" }}>{cur?.title}</div>
            <div style={{ fontSize:12.5, color:"var(--text-2)", lineHeight:1.65, marginBottom:18 }}>{cur?.body}</div>
            <div style={{ display:"flex", gap:4, marginBottom:18 }}>
              {DEMO_STEPS.map((_, i) => (
                <div key={i} style={{ flex:1, height:3, borderRadius:2, background: i <= step ? "var(--teal)" : "var(--line)", transition:"background 0.3s" }} />
              ))}
            </div>
            <div style={{ display:"flex", gap:8 }}>
              {step > 0 && (
                <button onClick={prev} style={{ flex:1, background:"var(--paper-3)", color:"var(--text-2)", border:"1px solid var(--line)", borderRadius:9, padding:"9px", fontSize:12.5, cursor:"pointer", fontWeight:600 }}>← Back</button>
              )}
              <button onClick={next} style={{ flex:2, background:"var(--navy)", color:"#fff", border:"none", borderRadius:9, padding:"9px", fontSize:12.5, fontWeight:700, cursor:"pointer" }}>
                {step === DEMO_STEPS.length - 1 ? "Finish tour ✓" : "Next →"}
              </button>
            </div>
            <button onClick={endTour} style={{ display:"block", width:"100%", background:"transparent", color:"var(--text-3)", border:"none", fontSize:11, cursor:"pointer", marginTop:10, padding:4 }}>Skip tour</button>
          </div>
        </>
      )}
    </>
  );
}

// ── DemoShell — Token gate ─────────────────────────────────────────────────────
function DemoShell({ children }) {
  const [status, setStatus] = React.useState("checking"); // checking|valid|invalid|expired|notoken
  const [stakeholder, setStakeholder] = React.useState(null);
  const token = new URLSearchParams(window.location.search).get("token");

  // Register global logEvent
  React.useEffect(() => {
    if (!token) return;
    window.__vinproLogEvent = async (event, payload = {}) => {
      try {
        await fbArrayAppend(token, "events", { event, ...payload, at: new Date().toISOString() });
      } catch { /* silently fail */ }
    };
    return () => { delete window.__vinproLogEvent; };
  }, [token]);

  React.useEffect(() => {
    // No token → show app directly (local dev / direct access)
    if (!token) { setStatus("notoken"); return; }

    // If Firebase not configured, skip validation
    if (DEMO_FB_PROJECT === "YOUR_FIREBASE_PROJECT_ID") {
      setStatus("valid");
      setStakeholder({ name: "Demo Visitor", company: "Demo", role: "" });
      setTimeout(() => { if (window.__vinproStartTour) window.__vinproStartTour(); }, 600);
      return;
    }

    (async () => {
      const doc = await fbGet(`tokens/${token}`);
      if (!doc) { setStatus("invalid"); return; }
      const data = parseFirestoreDoc(doc);
      if (!data) { setStatus("invalid"); return; }

      // Check expiry
      if (data.expiresAt) {
        const exp = new Date(data.expiresAt);
        if (exp < new Date()) { setStatus("expired"); return; }
      }

      // Log session
      await fbArrayAppend(token, "sessions", { startedAt: new Date().toISOString(), ua: navigator.userAgent.slice(0, 100) });
      await fbPatch(`tokens/${token}`, { viewCount: (data.viewCount || 0) + 1, firstViewedAt: data.firstViewedAt || new Date().toISOString() });

      setStakeholder(data);
      setStatus("valid");

      // Start tour after app loads
      setTimeout(() => { if (window.__vinproStartTour) window.__vinproStartTour(); }, 1200);
    })();
  }, [token]);

  const S = {
    wrap: { minHeight:"100vh", background:"var(--paper-2)", display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"'Manrope','Inter',system-ui,sans-serif" },
    card: { background:"#fff", border:"1px solid var(--line)", borderRadius:20, padding:44, maxWidth:380, width:"90%", textAlign:"center", boxShadow:"0 24px 60px rgba(11,31,94,0.12)" },
    icon: (bg) => ({ width:60, height:60, background:bg, borderRadius:16, display:"flex", alignItems:"center", justifyContent:"center", fontSize:24, margin:"0 auto 20px" }),
    title: { fontSize:20, fontWeight:800, color:"var(--navy)", marginBottom:8, letterSpacing:"-0.02em" },
    body: { fontSize:13, color:"var(--text-2)", lineHeight:1.7 }
  };

  if (status === "checking") {
    return (
      <div style={S.wrap}>
        <div style={{ textAlign:"center", color:"var(--text-3)", fontSize:14 }}>
          <div style={{ fontSize:32, marginBottom:16, opacity:0.3 }}>✨</div>
          Verifying access…
        </div>
      </div>
    );
  }
  if (status === "invalid") {
    return (
      <div style={S.wrap}>
        <div style={S.card}>
          <div style={S.icon("var(--red-soft)")}><span style={{color:"var(--red)"}}>⊗</span></div>
          <div style={S.title}>Invalid Link</div>
          <div style={S.body}>This demo link is not valid or has already been used.<br/>Contact your Vinpro Connect representative for a new link.</div>
        </div>
      </div>
    );
  }
  if (status === "expired") {
    return (
      <div style={S.wrap}>
        <div style={S.card}>
          <div style={S.icon("var(--amber-soft)")}><span style={{color:"var(--amber)"}}>⏱</span></div>
          <div style={S.title}>Link Expired</div>
          <div style={S.body}>This demo link has expired.<br/>Your representative will send a fresh one shortly.</div>
        </div>
      </div>
    );
  }

  // valid or notoken → show app (with personalised welcome if stakeholder set)
  return (
    <>
      {stakeholder?.name && status === "valid" && (
        <div style={{ position:"fixed", top:0, left:0, right:0, zIndex:20000, background:"var(--navy)", color:"#fff", fontSize:12, padding:"6px 20px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <span>👋 Welcome, <strong>{stakeholder.name}</strong> — {stakeholder.company}</span>
          <button onClick={() => { if(window.__vinproStartTour) window.__vinproStartTour(); }} style={{ background:"var(--teal)", color:"#fff", border:"none", borderRadius:6, padding:"3px 12px", fontSize:11.5, fontWeight:700, cursor:"pointer" }}>▶ Start Tour</button>
        </div>
      )}
      <div style={stakeholder?.name && status === "valid" ? { paddingTop:32 } : {}}>
        {children}
      </div>
    </>
  );
}

// ── DemoAdminPanel ─────────────────────────────────────────────────────────────
