const DEMO_BASE_URL = (typeof import_meta_env !== "undefined" && import_meta_env?.VITE_DEMO_URL) || (typeof window !== "undefined" ? window.location.origin : "");

function DemoAdminPanel() {
  const [authed, setAuthed] = React.useState(false);
  const [pw, setPw] = React.useState("");
  const [pwError, setPwError] = React.useState(false);
  const [tokens, setTokens] = React.useState([]);
  const [loading, setLoading] = React.useState(false);
  const [creating, setCreating] = React.useState(false);
  const [selected, setSelected] = React.useState(null);
  const [copied, setCopied] = React.useState(null);
  const [form, setForm] = React.useState({ name:"", company:"", role:"", expiryDays:7, notes:"" });

  const login = () => {
    if (pw === DEMO_ADMIN_PW || pw === "vinpro2026") { setAuthed(true); loadTokens(); }
    else { setPwError(true); setTimeout(() => setPwError(false), 1500); }
  };

  const loadTokens = async () => {
    setLoading(true);
    try {
      const r = await fetch(`${DEMO_FB_BASE}/tokens?key=${DEMO_FB_API_KEY}&pageSize=50&orderBy=createdAt desc`);
      const d = await r.json();
      const docs = (d.documents || []).map(doc => ({ id: doc.name.split("/").pop(), ...parseFirestoreDoc(doc) }));
      setTokens(docs);
    } catch { setTokens([]); }
    setLoading(false);
  };

  const generateId = () => Math.random().toString(36).slice(2, 10) + Math.random().toString(36).slice(2, 6);

  const createToken = async () => {
    if (!form.name || !form.company) return;
    const id = generateId();
    const exp = new Date(); exp.setDate(exp.getDate() + Number(form.expiryDays));
    try {
      await fetch(`${DEMO_FB_BASE}/tokens?key=${DEMO_FB_API_KEY}&documentId=${id}`, {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ fields: {
          name: { stringValue: form.name },
          company: { stringValue: form.company },
          role: { stringValue: form.role },
          notes: { stringValue: form.notes },
          createdAt: { stringValue: new Date().toISOString() },
          expiresAt: { stringValue: exp.toISOString() },
          viewCount: { integerValue: 0 }
        }})
      });
      setForm({ name:"", company:"", role:"", expiryDays:7, notes:"" });
      setCreating(false);
      await loadTokens();
    } catch (e) { alert("Error creating token. Check Firebase config."); }
  };

  const copyLink = (id) => {
    navigator.clipboard.writeText(`${DEMO_BASE_URL}/?token=${id}`);
    setCopied(id); setTimeout(() => setCopied(null), 2000);
  };

  const timeAgo = (iso) => {
    if (!iso) return "—";
    const diff = Date.now() - new Date(iso).getTime();
    const m = Math.floor(diff / 60000);
    if (m < 1) return "just now";
    if (m < 60) return `${m}m ago`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}h ago`;
    return `${Math.floor(h / 24)}d ago`;
  };

  const parseEvents = (tok) => {
    const raw = tok.events;
    if (!raw) return [];
    try { return typeof raw === "string" ? JSON.parse(raw) : (Array.isArray(raw) ? raw : []); }
    catch { return []; }
  };

  if (!authed) {
    return (
      <div style={{ minHeight:"100vh", background:"var(--paper-2)", display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"'Manrope','Inter',system-ui,sans-serif" }}>
        <div style={{ background:"#fff", border:"1px solid var(--line)", borderRadius:16, padding:40, width:360, boxShadow:"var(--shadow-lg)" }}>
          <div style={{ fontSize:20, fontWeight:800, color:"var(--navy)", marginBottom:4 }}>Demo Admin Panel</div>
          <div style={{ fontSize:13, color:"var(--text-2)", marginBottom:28 }}>Vinpro Connect — Stakeholder Management</div>
          <input type="password" placeholder="Admin password" value={pw}
            onChange={e => setPw(e.target.value)} onKeyDown={e => e.key === "Enter" && login()}
            style={{ width:"100%", background:"var(--paper-3)", border:`1px solid ${pwError ? "var(--red)" : "var(--line-2)"}`, borderRadius:10, padding:"11px 14px", fontSize:13.5, color:"var(--navy)", outline:"none", marginBottom:12 }} />
          <button onClick={login} style={{ width:"100%", background:"var(--navy)", color:"#fff", fontWeight:700, fontSize:14, padding:12, borderRadius:10, border:"none", cursor:"pointer" }}>Sign in →</button>
          {pwError && <div style={{ fontSize:12, color:"var(--red)", marginTop:8, textAlign:"center" }}>Incorrect password</div>}
        </div>
      </div>
    );
  }

  const detailTok = selected ? tokens.find(t => t.id === selected) : null;
  const detailEvents = detailTok ? parseEvents(detailTok) : [];

  return (
    <div style={{ minHeight:"100vh", background:"var(--paper-2)", fontFamily:"'Manrope','Inter',system-ui,sans-serif", color:"var(--navy)" }}>
      {/* Header */}
      <div style={{ background:"var(--navy)", color:"#fff", padding:"14px 28px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
        <div style={{ fontWeight:800, fontSize:16 }}>Vinpro Connect — Demo Admin</div>
        <div style={{ fontSize:12, opacity:0.6 }}>{tokens.length} links · {tokens.filter(t => (t.viewCount || 0) > 0).length} viewed</div>
      </div>

      <div style={{ padding:28 }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20 }}>
          <div style={{ fontSize:18, fontWeight:800 }}>Stakeholder Links</div>
          <button onClick={() => setCreating(true)} className="dl-btn dl-btn-primary">+ New Link</button>
        </div>

        {creating && (
          <div style={{ background:"#fff", border:"1px solid var(--teal)", borderRadius:14, padding:24, marginBottom:20 }}>
            <div style={{ fontSize:15, fontWeight:700, marginBottom:18 }}>Create Stakeholder Link</div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12, marginBottom:12 }}>
              {[
                { k:"name", l:"Name *", ph:"Rahul Verma" },
                { k:"company", l:"Company *", ph:"Infosys BPM" },
                { k:"role", l:"Title", ph:"VP – HR" },
                { k:"expiryDays", l:"Valid for (days)", ph:"7", t:"number" }
              ].map(f => (
                <div key={f.k}>
                  <div style={{ fontSize:11, fontWeight:600, color:"var(--text-3)", marginBottom:5, textTransform:"uppercase", letterSpacing:"0.07em" }}>{f.l}</div>
                  <input type={f.t||"text"} placeholder={f.ph} value={form[f.k]}
                    onChange={e => setForm(p => ({ ...p, [f.k]: e.target.value }))}
                    className="dl-input" style={{ width:"100%" }} />
                </div>
              ))}
            </div>
            <div style={{ marginBottom:16 }}>
              <div style={{ fontSize:11, fontWeight:600, color:"var(--text-3)", marginBottom:5, textTransform:"uppercase", letterSpacing:"0.07em" }}>Internal notes</div>
              <input placeholder="e.g. Met at SaaS Conf, interested in payroll" value={form.notes}
                onChange={e => setForm(p => ({ ...p, notes: e.target.value }))} className="dl-input" style={{ width:"100%" }} />
            </div>
            <div style={{ display:"flex", gap:8 }}>
              <button onClick={createToken} disabled={!form.name || !form.company} className="dl-btn dl-btn-brand">Generate Link</button>
              <button onClick={() => setCreating(false)} className="dl-btn dl-btn-outline">Cancel</button>
            </div>
          </div>
        )}

        {loading ? (
          <div style={{ color:"var(--text-3)", padding:20 }}>Loading…</div>
        ) : (
          <div style={{ background:"#fff", border:"1px solid var(--line)", borderRadius:14, overflow:"hidden" }}>
            <table style={{ width:"100%", borderCollapse:"collapse" }}>
              <thead>
                <tr style={{ background:"var(--paper-3)" }}>
                  {["Stakeholder","Company","Views","Last Active","Modules Seen","Actions"].map(h => (
                    <th key={h} style={{ fontSize:10, color:"var(--text-3)", textAlign:"left", padding:"12px 16px", textTransform:"uppercase", letterSpacing:"0.08em", fontWeight:600 }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {tokens.map((t) => {
                  const evts = parseEvents(t);
                  const mods = [...new Set(evts.filter(e => e.event === "module_view").map(e => e.module))];
                  const lastEvt = evts.slice(-1)[0]?.at;
                  const viewed = (t.viewCount || 0) > 0;
                  return (
                    <tr key={t.id} style={{ borderTop:"1px solid var(--line)", cursor:"pointer", background: selected === t.id ? "var(--paper-3)" : "transparent" }}
                      onClick={() => setSelected(selected === t.id ? null : t.id)}>
                      <td style={{ padding:"12px 16px" }}>
                        <div style={{ fontWeight:600, fontSize:13.5 }}>{t.name}</div>
                        <div style={{ fontSize:11, color:"var(--text-3)" }}>{t.role}</div>
                      </td>
                      <td style={{ padding:"12px 16px", fontSize:13, color:"var(--text-2)" }}>{t.company}</td>
                      <td style={{ padding:"12px 16px" }}>
                        <span style={{ fontSize:16, fontWeight:800, color: viewed ? "var(--green)" : "var(--text-3)" }}>{t.viewCount || 0}</span>
                      </td>
                      <td style={{ padding:"12px 16px", fontSize:12, color:"var(--text-2)" }}>{timeAgo(lastEvt || t.firstViewedAt)}</td>
                      <td style={{ padding:"12px 16px" }}>
                        <div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>
                          {mods.length === 0 ? <span style={{ fontSize:11, color:"var(--text-3)" }}>—</span> :
                            mods.map(m => <span key={m} className="dl-pill info" style={{ fontSize:10 }}>{m}</span>)}
                        </div>
                      </td>
                      <td style={{ padding:"12px 16px" }}>
                        <button onClick={e => { e.stopPropagation(); copyLink(t.id); }} className="dl-btn dl-btn-outline dl-btn-sm"
                          style={{ color: copied === t.id ? "var(--green)" : undefined }}>
                          {copied === t.id ? "✓ Copied" : "Copy Link"}
                        </button>
                      </td>
                    </tr>
                  );
                })}
                {tokens.length === 0 && (
                  <tr><td colSpan={6} style={{ padding:40, textAlign:"center", color:"var(--text-3)", fontSize:13 }}>No links yet. Create your first above.</td></tr>
                )}
              </tbody>
            </table>
          </div>
        )}

        {detailTok && (
          <div style={{ background:"#fff", border:"1px solid var(--line)", borderRadius:14, padding:24, marginTop:20 }}>
            <div style={{ fontSize:16, fontWeight:800, marginBottom:4 }}>{detailTok.name}</div>
            <div style={{ fontSize:12, color:"var(--text-2)", marginBottom:20 }}>{detailTok.company} · {detailTok.role}</div>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:14, marginBottom:20 }}>
              {[
                { l:"Total Views", v: detailTok.viewCount || 0 },
                { l:"Modules Explored", v: [...new Set(detailEvents.filter(e=>e.event==="module_view").map(e=>e.module))].length },
                { l:"AI Questions", v: detailEvents.filter(e=>e.event==="ai_question").length }
              ].map((s,i) => (
                <div key={i} className="dl-stat">
                  <div className="dl-stat-label">{s.l}</div>
                  <div className="dl-stat-value">{s.v}</div>
                </div>
              ))}
            </div>
            {detailEvents.filter(e=>e.event==="ai_question").length > 0 && (
              <div style={{ marginBottom:16 }}>
                <div style={{ fontSize:12, fontWeight:700, color:"var(--text-3)", marginBottom:10, textTransform:"uppercase", letterSpacing:"0.07em" }}>Questions asked to AI Copilot</div>
                {detailEvents.filter(e=>e.event==="ai_question").map((e,i) => (
                  <div key={i} style={{ background:"var(--paper-3)", borderRadius:8, padding:"9px 14px", marginBottom:6, fontSize:13, color:"var(--text-2)", borderLeft:"3px solid var(--teal)" }}>{e.question}</div>
                ))}
              </div>
            )}
            <div style={{ background:"var(--paper-3)", borderRadius:10, padding:14, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <code style={{ fontSize:12, color:"var(--text-2)" }}>{DEMO_BASE_URL}/?token={detailTok.id}</code>
              <button onClick={() => copyLink(detailTok.id)} className="dl-btn dl-btn-outline dl-btn-sm">
                {copied === detailTok.id ? "✓ Copied" : "Copy"}
              </button>
            </div>
            {detailTok.notes && <div style={{ marginTop:10, fontSize:12, color:"var(--text-3)", fontStyle:"italic" }}>Notes: {detailTok.notes}</div>}
          </div>
        )}
      </div>
    </div>
  );
}
